"use client";

import { useState } from "react";
import Image from "next/image";
import Link from "next/link";
import Counter from "@/components/ui/Counter";
import VideoModal from "@/components/ui/VideoModal";
import { PlayButton } from "@/components/ui/PlayButton";

export default function Hero() {
  const [open, setOpen] = useState(false);

  return (
    <section className="relative overflow-hidden text-white">

      {/* Gradient */}
      <div className="absolute inset-0 bg-gradient-to-br from-blue-600 via-indigo-600 to-purple-700" />

      {/* Subtle Parallax Background */}
      <div className="absolute inset-0 opacity-10">
        <div className="absolute w-[600px] h-[600px] bg-white rounded-full blur-[150px] top-[-200px] left-[-200px] animate-slowFloat" />
      </div>

      {/* Content */}
      <div className="relative z-10 max-w-7xl mx-auto px-6 pt-32 pb-36 text-center">

        <h1 className="text-4xl sm:text-5xl lg:text-6xl font-bold leading-tight">
          Empowering Your Business <br />
          with Data-Driven Marketing
        </h1>

        <div className="flex items-center justify-center gap-6 mt-10">
          <Link
            href="/services"
            className="px-8 py-3 bg-white text-indigo-700 font-semibold rounded-full"
          >
            Our Services
          </Link>

          <PlayButton onClick={() => setOpen(true)} />
        </div>
      </div>

      {/* Stats with Counter */}
      <div className="relative z-10 max-w-6xl mx-auto px-6 pb-20">
        <div className="grid grid-cols-2 md:grid-cols-4 gap-8 text-center border-t border-white/20 pt-10">
          <div>
            <h3 className="text-2xl font-bold">
              <Counter value={20} suffix=".5K" />
            </h3>
            <p className="text-white/80 text-sm">Projects Done</p>
          </div>
          <div>
            <h3 className="text-2xl font-bold">
              <Counter value={100} suffix=".5K" />
            </h3>
            <p className="text-white/80 text-sm">Happy Clients</p>
          </div>
          <div>
            <h3 className="text-2xl font-bold">
              <Counter value={150} suffix=".5K" />
            </h3>
            <p className="text-white/80 text-sm">Team Members</p>
          </div>
          <div className="flex items-center justify-center">
            <PlayButton onClick={() => setOpen(true)} />
          </div>
        </div>
      </div>

      {/* Video Modal */}
      <VideoModal
        open={open}
        onClose={() => setOpen(false)}
        youtubeId="WUB2pSkwN2M" // or remove and use videoSrc="/video.mp4"
      />

    </section>
  );
}










